{"type": "post", "post": {"team": "customer_support", "channel": "cs_representatives", "user": "john_doe", "message": "Good morning team, the new training material for the updated software is now available on the internal server. Please ensure to review it before the meeting tomorrow.", "created_at": 1620500000000}}
